class Transport(Protocol):
    def call(self, method: str, path: str,
             body: dict | None, timeout: float) -> dict: ...
    def open_blob(self, path: str, mode: str) -> IO[bytes]: ...   # provider-only; loopback may NotImplementedError
    def health(self) -> dict: ...
    def close(self) -> None: ...

discovery.code_sketch:
from jnius import autoclass

PythonActivity = autoclass('org.kivy.android.PythonActivity')
PackageManager = autoclass('android.content.pm.PackageManager')
Uri = autoclass('android.net.Uri')

def discover():
    activity = PythonActivity.mActivity
    pm = activity.getPackageManager()
    flags = 0
    providers = pm.queryContentProviders(None, 0, flags)
    for info in providers.toArray():
        authority = info.authority
        if authority.endswith('.aztcollab'):
            uri = Uri.parse(f'content://{authority}/v1/health')
            try:
                resolver = activity.getContentResolver()
                bundle = resolver.call(uri, 'ping', None, None)
                if bundle is not None:
                    return AndroidCPTransport(authority)
            except Exception:
                continue
    return None
